class PaymentRouter:
    def __init__(self):
        self._rules: list[RoutingRule] = []

    def add_rule(self, rule: RoutingRule):
        self._rules.append(rule)

    def route(self, payment: Payment) -> PaymentChannel:
        for rule in sorted(self._rules, key=lambda r: r.priority):
            if rule.matches(payment):
                return rule.channel
        return DefaultChannel()

class RoutingRule:
    def __init__(self, condition, channel, priority=0):
        self.condition = condition
        self.channel = channel
        self.priority = priority

    def matches(self, payment: Payment) -> bool:
        return self.condition(payment)

router = PaymentRouter()
router.add_rule(RoutingRule(lambda p: p.amount < 100, Alipay(), 1))
router.add_rule(RoutingRule(lambda p: p.amount >= 100, WechatPay(), 2))

class InventoryService:
    def __init__(self):
        self._locks: dict[str, bool] = {}

    def reserve(self, sku: str, quantity: int) -> bool:
        """预扣库存"""
        available = self.get_available(sku)
        if available < quantity:
            return False
        self._locks[sku] = self._locks.get(sku, 0) + quantity
        return True

    def confirm(self, sku: str, quantity: int):
        """确认扣减"""
        self._locks[sku] -= quantity

    def release(self, sku: str, quantity: int):
        """释放预扣"""
        if sku in self._locks:
            self._locks[sku] -= quantity

    def get_available(self, sku: str) -> int:
        total = self._get_stock(sku)
        locked = self._locks.get(sku, 0)
        return total - locked

class RiskScorer:
    def __init__(self):
        self._rules: list[RiskRule] = []

    def add_rule(self, rule: RiskRule):
        self._rules.append(rule)

    def score(self, transaction: Transaction) -> int:
        total_score = 0
        for rule in self._rules:
            if rule.matches(transaction):
                total_score += rule.score
                if total_score >= rule.threshold:
                    break
        return total_score

class RiskRule:
    def __init__(self, name, condition, score, threshold=100):
        self.name = name
        self.condition = condition
        self.score = score
        self.threshold = threshold

    def matches(self, transaction: Transaction) -> bool:
        return self.condition(transaction)

