scorer.add_rule(RiskRule("high_amount", lambda t: t.amount > 10000, 50))
scorer.add_rule(RiskRule("new_user", lambda t: t.user_age_days < 7, 30))
scorer.add_rule(RiskRule("foreign_ip", lambda t: t.ip_country != t.user_country, 40))

class RecommendationRanker:
    def __init__(self):
        self._features: list[RankingFeature] = []

    def add_feature(self, feature: RankingFeature):
        self._features.append(feature)

    def rank(self, items: list[Item], user: User) -> list[Item]:
        scored = []
        for item in items:
            score = 0.0
            for feature in self._features:
                score += feature.compute(item, user) * feature.weight
            scored.append((score, item))

        scored.sort(key=lambda x: x[0], reverse=True)
        return [item for _, item in scored]

